/**
 * Config discovery, validation, and env interpolation.
 *
 * Config lookup order (first existing file wins):
 *   1. <cwd>/.pi-conductor-analytics.json
 *   2. <cwd>/.pi/conductor-analytics.json
 *   3. <home>/.pi-conductor-analytics.json
 *   4. <home>/.config/pi-conductor/analytics.json
 */

import { existsSync, readFileSync } from "node:fs";
import { homedir } from "node:os";
import { join } from "node:path";
import type { AnalyticsConfig, ResolvedConfig } from "./types.js";

// ─── Helpers ───────────────────────────────────────────────────────────

const { env } = process;

/**
 * Interpolate `${ENV_VAR}` patterns in string values.
 * Leaves unrecognized patterns as-is.
 */
export function interpolateEnv(value: string): string {
  return value.replace(/\$\{([A-Za-z_][A-Za-z0-9_]*)\}/g, (_, name: string) => {
    return env[name] ?? `$\{${name}}`;
  });
}

// ─── Config file paths ──────────────────────────────────────────────────

function* configPaths(cwd: string, home: string): Generator<string> {
  yield join(cwd, ".pi-conductor-analytics.json");
  yield join(cwd, ".pi", "conductor-analytics.json");
  yield join(home, ".pi-conductor-analytics.json");
  yield join(home, ".config", "pi-conductor", "analytics.json");
}

// ─── Defaults ───────────────────────────────────────────────────────────

const DEFAULTS: ResolvedConfig = {
  enabled: true,
  endpoint: undefined,
  headers: {},
  batch: {
    enabled: true,
    maxRecords: 25,
    flushIntervalMs: 1000,
  },
  request: {
    timeoutMs: 5000,
    maxRetries: 2,
  },
};

// ─── Config loading ─────────────────────────────────────────────────────

/**
 * Load and resolve config from disk or return defaults.
 *
 * @param cwd  Current working directory (probe dirs 1–2).
 * @param home  Home directory (probe dirs 3–4). Defaults to `os.homedir()`.
 * @returns Tuple of [resolved config, loaded from path or null, warnings[]].
 */
export function loadConfig(
  cwd: string,
  home: string = homedir(),
): [ResolvedConfig, string | null, string[]] {
  const warnings: string[] = [];
  let raw: AnalyticsConfig | undefined;
  let sourcePath: string | null = null;

  // Find first existing config file.
  for (const p of configPaths(cwd, home)) {
    if (existsSync(p)) {
      try {
        const content = readFileSync(p, "utf-8");
        raw = JSON.parse(content) as AnalyticsConfig;
        sourcePath = p;
        break;
      } catch (err) {
        warnings.push(`Failed to parse config at ${p}: ${(err as Error).message}`);
      }
    }
  }

  if (raw === undefined || sourcePath === null) {
    // No config found — return defaults with enabled=false so the plugin
    // loads but does not post.
    return [{ ...DEFAULTS, enabled: false }, null, warnings];
  }

  return validateAndResolve(raw, sourcePath, warnings);
}

/**
 * Validate a raw config object and resolve with defaults.
 */
export function validateAndResolve(
  raw: AnalyticsConfig,
  source: string,
  warnings: string[],
): [ResolvedConfig, string, string[]] {
  const resolved: ResolvedConfig = { ...DEFAULTS };

  // enabled
  if (raw.enabled === false) {
    resolved.enabled = false;
    return [resolved, source, warnings];
  }

  // endpoint — required when enabled is not false
  if (typeof raw.endpoint !== "string" || raw.endpoint.trim().length === 0) {
    warnings.push(`Config at ${source}: "endpoint" is required when enabled. Disabling reporting.`);
    resolved.enabled = false;
    return [resolved, source, warnings];
  }

  // Validate endpoint URL
  const endpoint = raw.endpoint.trim();
  try {
    const url = new URL(endpoint);
    if (url.protocol !== "http:" && url.protocol !== "https:") {
      warnings.push(
        `Config at ${source}: "endpoint" protocol must be http: or https:, got "${url.protocol}". Disabling reporting.`,
      );
      resolved.enabled = false;
      return [resolved, source, warnings];
    }
  } catch {
    warnings.push(`Config at ${source}: "endpoint" is not a valid URL. Disabling reporting.`);
    resolved.enabled = false;
    return [resolved, source, warnings];
  }
  resolved.endpoint = endpoint;

  // headers
  if (raw.headers !== undefined && typeof raw.headers === "object" && !Array.isArray(raw.headers)) {
    const interpolated: Record<string, string> = {};
    for (const [key, value] of Object.entries(raw.headers)) {
      if (typeof value === "string") {
        interpolated[key] = interpolateEnv(value);
      }
    }
    resolved.headers = interpolated;
  }

  // batch
  if (raw.batch !== undefined && typeof raw.batch === "object" && !Array.isArray(raw.batch)) {
    if (typeof raw.batch.enabled === "boolean") resolved.batch.enabled = raw.batch.enabled;
    if (typeof raw.batch.maxRecords === "number" && raw.batch.maxRecords > 0) {
      resolved.batch.maxRecords = raw.batch.maxRecords;
    }
    if (typeof raw.batch.flushIntervalMs === "number" && raw.batch.flushIntervalMs > 0) {
      resolved.batch.flushIntervalMs = raw.batch.flushIntervalMs;
    }
  }

  // request
  if (raw.request !== undefined && typeof raw.request === "object" && !Array.isArray(raw.request)) {
    if (typeof raw.request.timeoutMs === "number" && raw.request.timeoutMs > 0) {
      resolved.request.timeoutMs = raw.request.timeoutMs;
    }
    if (typeof raw.request.maxRetries === "number" && raw.request.maxRetries >= 0) {
      resolved.request.maxRetries = raw.request.maxRetries;
    }
  }

  return [resolved, source, warnings];
}

// ─── Module-level state cache ───────────────────────────────────────────

let cachedConfig: ResolvedConfig | undefined;
let cachedWarnings: string[] = [];
let cachedSourcePath: string | null = null;

/**
 * Get or load the analytics configuration.
 *
 * First call probes config paths and caches the result.
 * Subsequent calls return the cached config (caller must re-load on demand).
 *
 * @param cwd  Override CWD for testing. Defaults to `process.cwd()`.
 * @returns Tuple of [ResolvedConfig, source path or null, warnings[]].
 */
export function getConfig(cwd?: string): [ResolvedConfig, string | null, string[]] {
  if (cachedConfig !== undefined) {
    return [cachedConfig, cachedSourcePath, [...cachedWarnings]];
  }

  const wd = cwd ?? process.cwd();
  const home = homedir();
  const [config, source, warnings] = loadConfig(wd, home);

  cachedConfig = config;
  cachedSourcePath = source;
  cachedWarnings = warnings;

  return [config, source, warnings];
}

/** Clear the cached config (useful for testing). */
export function clearConfigCache(): void {
  cachedConfig = undefined;
  cachedSourcePath = null;
  cachedWarnings = [];
}

/**
 * JSONL backstop / watermark — per-run watermark tracking to ship
 * records that may have been missed during a network outage or
 * late plugin load.
 *
 * Each run gets a small JSON sidecar file alongside the run's JSONL:
 *   <run_base>/.pi-conductor/runs/<run_id>.watermark.json
 *
 * The watermarks directory is derived from the conductor run base:
 *   <cwd>/.pi-conductor/runs/
 *
 * On `session_start`, the backstop walks .pi-conductor/runs/*.jsonl
 * files and ships any records past the per-run watermark.
 */

import { existsSync, readdirSync, readFileSync, writeFileSync } from "node:fs";
import { join } from "node:path";
import type { DeliveryQueue } from "./queue.js";
import type { ResolvedConfig } from "./types.js";

// ─── Default run directory ──────────────────────────────────────────────

/**
 * The default directory where pi-conductor stores run JSONL files.
 * Mirrors `DEFAULT_RUN_BASE_DIR` in pi-conductor's start.ts.
 */
export const DEFAULT_RUN_BASE_DIR = ".pi-conductor/runs";

// ─── Watermark file helpers ─────────────────────────────────────────────

interface WatermarkData {
  lastSentIndex: number;
}

function watermarkPath(runsDir: string, runId: string): string {
  return join(runsDir, `${runId}.watermark.json`);
}

function readWatermark(runsDir: string, runId: string): number {
  const wmPath = watermarkPath(runsDir, runId);
  if (!existsSync(wmPath)) return -1;
  try {
    const data = JSON.parse(readFileSync(wmPath, "utf-8")) as WatermarkData;
    return typeof data.lastSentIndex === "number" ? data.lastSentIndex : -1;
  } catch {
    return -1;
  }
}

function writeWatermark(runsDir: string, runId: string, lastSentIndex: number): void {
  const wmPath = watermarkPath(runsDir, runId);
  const data: WatermarkData = { lastSentIndex };
  writeFileSync(wmPath, JSON.stringify(data), "utf-8");
}

// ─── Run file helpers ───────────────────────────────────────────────────

interface RunFile {
  runId: string;
  filePath: string;
}

/**
 * Discover JSONL run files in the runs directory.
 */
function discoverRuns(runsDir: string): RunFile[] {
  if (!existsSync(runsDir)) return [];
  try {
    const entries = readdirSync(runsDir);
    const seen = new Set<string>();
    const result: RunFile[] = [];
    for (const entry of entries) {
      // Match `*.jsonl` but not `*.watermark.json`
      if (entry.endsWith(".jsonl") && !entry.endsWith(".watermark.json")) {
        const runId = entry.slice(0, -6); // strip ".jsonl"
        if (!seen.has(runId)) {
          seen.add(runId);
          result.push({ runId, filePath: join(runsDir, entry) });
        }
      }
    }
    return result.sort((a, b) => a.runId.localeCompare(b.runId));
  } catch {
    return [];
  }
}

/**
 * Read records from a JSONL file starting from a given index.
 * Returns the records and the count of lines read.
 */
function readRecordsFrom(
  filePath: string,
  startIndex: number,
): { records: unknown[]; lineCount: number } {
  if (!existsSync(filePath)) return { records: [], lineCount: 0 };
  try {
    const content = readFileSync(filePath, "utf-8");
    const lines = content.trim().split("\n");
    const records: unknown[] = [];
    for (let i = startIndex + 1; i < lines.length; i++) {
      const line = lines[i]?.trim();
      if (line !== undefined && line.length > 0) {
        try {
          records.push(JSON.parse(line));
        } catch {
          // Skip unparseable lines
        }
      }
    }
    return { records, lineCount: lines.length };
  } catch {
    return { records: [], lineCount: 0 };
  }
}

// ─── Backstop execution ─────────────────────────────────────────────────

/**
 * Run the JSONL backstop: walk all known JSONL run files and enqueue
 * any records past the per-run watermark.
 *
 * @param cwd   The current working directory (probe <cwd>/.pi-conductor/runs/).
 * @param queue  The delivery queue to enqueue records into.
 * @param config  The resolved config (used for batching, not delivery here).
 * @returns The number of backfill records enqueued.
 */
export function runBackstop(cwd: string, queue: DeliveryQueue, _config: ResolvedConfig): number {
  const runsDir = join(cwd, DEFAULT_RUN_BASE_DIR);
  if (!existsSync(runsDir)) return 0;

  const runs = discoverRuns(runsDir);
  let totalEnqueued = 0;

  for (const run of runs) {
    const watermark = readWatermark(runsDir, run.runId);
    const { records, lineCount } = readRecordsFrom(run.filePath, watermark);

    for (const record of records) {
      queue.enqueue(record);
      totalEnqueued++;
    }

    // Update watermark to reflect all lines read
    if (lineCount > watermark + 1) {
      writeWatermark(runsDir, run.runId, lineCount - 1);
    }
  }

  return totalEnqueued;
}

/**
 * Update the watermark for a single run after the queue delivers a record.
 *
 * @param runId   The run ID to update.
 * @param index   The 0-based index of the last-sent record in the JSONL.
 */
export function updateWatermark(runId: string, index: number, cwd: string): void {
  const runsDir = join(cwd, DEFAULT_RUN_BASE_DIR);
  writeWatermark(runsDir, runId, index);
}

/**
 * Public types for the pi-conductor analytics plugin.
 */

/** Configuration shape for the analytics plugin. */
export interface AnalyticsConfig {
  /** Master switch. Default: true. */
  enabled?: boolean;
  /** HTTP(S) endpoint to POST records to. Required when enabled is not false. */
  endpoint?: string;
  /** Custom HTTP headers to include in every POST. */
  headers?: Record<string, string>;
  /** Batching configuration. */
  batch?: {
    /** Enable batching. Default: true. */
    enabled?: boolean;
    /** Maximum records per batch POST. Default: 25. */
    maxRecords?: number;
    /** Maximum interval in ms before a partial batch is flushed. Default: 1000. */
    flushIntervalMs?: number;
  };
  /** Request-level configuration. */
  request?: {
    /** Request timeout in ms. Default: 5000. */
    timeoutMs?: number;
    /** Maximum retries per failed request. Default: 2. */
    maxRetries?: number;
  };
}

/** Resolved config with all defaults applied. */
export interface ResolvedConfig {
  enabled: boolean;
  endpoint: string | undefined;
  headers: Record<string, string>;
  batch: {
    enabled: boolean;
    maxRecords: number;
    flushIntervalMs: number;
  };
  request: {
    timeoutMs: number;
    maxRetries: number;
  };
}

/** The envelope sent to the configured endpoint. */
export interface AnalyticsEnvelope {
  plugin: "pi-conductor-analytics-plugin";
  plugin_version: string;
  schema_version: 1;
  sent_at: string;
  cwd: string;
  source: "pi.events:conductor:record";
  records: unknown[];
}

/** Queue item representing a record to be delivered. */
export interface QueueItem {
  records: unknown[];
}

/** Diagnostic counters exposed by the delivery queue. */
export interface QueueStats {
  enqueued: number;
  delivered: number;
  failed: number;
  dropped: number;
  pending: number;
}

/** Internal queue state for testing and diagnostics. */
export interface QueueDiagnostics {
  stats: QueueStats;
  overflowCount: number;
}

/** Per-run watermark tracking the last-sent record index. */
export interface RunWatermark {
  runId: string;
  lastSentIndex: number;
}

/**
 * pi-conductor-analytics-plugin public API.
